import classes from "./Input.module.css";

const Input = (props) => {
  // console.log("RERENDERED INPUT");

  if (props.hasError) {
  }
  
  return (
    <div className={classes["container"]}>
      {props.label && (
        <label className={classes["label"]}>
          {props.label}
          {props.hasError && <span> - Login or password is invalid</span>}
        </label>
      )}
      <div className={classes["input-wrapper"]}>
        <input
          className={classes["input"]}
          name={props.name}
          id={props.id}
          type={props.type}
          aria-label={props.label}
          autoComplete="off"
          onChange={props.onChange}
          onBlur={props.onBlur}
          value={props.value}
        ></input>
      </div>
    </div>
  );
};
export default Input;
